window.__QUIZ_DATA__=[{"id":"objective>Geography>1998>1","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Use the map of DIKWA DISTRICT to answer the question       Dikwa's growth can best be explained by its importance as a","images":["data:image/png;base64,"],"options":{"A":"fishing port","B":"nodal town","C":"mining town","D":"river port"},"answer":"B","explanation":"Dikwa isa town which is at the junction of many routes. Other towns are tied to Dikwa by the railway transportation system. Hence, Dikwa's growth can best be explained by its importance as a nodal town.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>2","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DIKWA DISTRICT to answer the question     The feature marked Y is a","images":["data:image/png;base64,"],"options":{"A":"ridge","B":"hill","C":"col","D":"plain"},"answer":"B","explanation":"The feature marked Y is an isolated hill. It is a hill which stands apart or is far removed from other hills or highlands.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>3","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DIKWA DISTRICT to answer the question     The contour interval is","images":["data:image/png;base64,"],"options":{"A":"50m","B":"100m","C":"500m","D":"700m"},"answer":"B","explanation":"According to the map, The contour interval i.e the distance between two contour lines is 100m.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>4","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Use the map of DIKWA DISTRICT to answer the question     How many tributaries has River Maira?","images":["data:image/png;base64,"],"options":{"A":"One","B":"Two","C":"Three","D":"Four"},"answer":"C","explanation":"A tributary is a stream that feeds into a larger stream or river. River Maira has three tributaries as shown by the map","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>5","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DIKWA DISTRICT to answer the question     If a cross profile is drawn from M to N which of the following shapes will it take?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"The cross profile is an highland whose peak is higher than the peak of the highland between M and N.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>6","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Use the map of DIKWA DISTRICT to answer the question     The natural vegetation in the north-western part of the map is most likely to be","images":["data:image/png;base64,"],"options":{"A":"Mediterranean forest","B":"montane forest","C":"rain forest","D":"savanna"},"answer":"D","explanation":"In the north-western part of the map, grasses are dominant and present in large quantity as shown on the map. Due to the presence of grasses, the vegetation is most likely to be savanna.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>7","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DIKWA DISTRICT to answer the question     Which of the following settlements will be visible from Takwa?","images":["data:image/png;base64,"],"options":{"A":"Dawa","B":"Dikwa","C":"Kauna","D":"Yilam"},"answer":"D","explanation":"Yilam will be visible from Takwa because of the absence of highlands between them.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>8","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Use the map of DIKWA DISTRICT to answer the question     The approximate bearing of Bundu from Tasima is","images":["data:image/png;base64,"],"options":{"A":"045o","B":"065o","C":"133o","D":"227o"},"answer":"C","explanation":"The approximate bearing of Bundu from Tasima is 133o","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>9","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Use the map of DIKWA DISTRICT to answer the question     The predominant occupation of the people at Koras is likely to be","images":["data:image/png;base64,"],"options":{"A":"rice cultivation","B":"lumbering","C":"mining","D":"livestock farming"},"answer":"D","explanation":"Koras is a ruralThe predominant occupation of the people at Koras is likely to be livestock farming","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>10","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Use the map of DIKWA DISTRICT to answer the question     Which of the following is true of the River Maira?","images":["data:image/png;base64,"],"options":{"A":"flows into the ocean","B":"has meanders","C":"is seasonal","D":"flows from the north-eastern highlands."},"answer":"D","explanation":"According to the map, River Maria flows from the north-eastern highlands.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>11","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Stars tend to form clusters known as","images":[],"options":{"A":"satellites","B":"Adromeda spiral","C":"planets","D":"galaxies"},"answer":"D","explanation":"Stars tend to form clusters known as galaxies. A galaxy is a gravitationally bound system of stars, stellar remnants, interstellar gas, dust, and dark matter. The other options are not correct because satellites are objects that orbit a planet, the Andromeda Spiral is a specific galaxy, and planets are celestial bodies orbiting a star.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>12","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The earth's axis is inclined to the plane of the ecliptic at an angle of","images":[],"options":{"A":"90o","B":"66(1/2)o","C":"50o","D":"23(1/2)o"},"answer":"B","explanation":"The earth's axis is inclined to the plane of the ecliptic at an angle of 66(1/2)o","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>13","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"When molten magma solidifies along bedding planes, the feature formed is known as","images":[],"options":{"A":"sill","B":"basalt","C":"lava","D":"batholith"},"answer":"A","explanation":"sills results when an intrusion of magma is made horizontally along the bedding planes of sedimentary rocks.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>14","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Standard time zones are created because","images":[],"options":{"A":"of the inconvenience of adjusting watches by travellers","B":"of the perculiar shapes and locations of some countries","C":"of the great east-west stretch","D":"all countries on the same meridian agreed to keep the same time"},"answer":"A","explanation":"To solve the problem of inconvenience of adjusting watches by travellers, Standard time zones were created.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>15","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"All the following rocks are metamorphic except","images":[],"options":{"A":"gneiss","B":"marble","C":"gabbro","D":"slate"},"answer":"C","explanation":"Gnesis, marble,slate,quartzite,schist and graphite are all examples of metamorphic rocks. Gabbro is an example of igneous rocks","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>16","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following statements is not correct about sedimentary rocks? They","images":[],"options":{"A":"could be formed by water","B":"are usually in layers","C":"are non-crystalline","D":"are formed in upland areas"},"answer":"D","explanation":"Sedimentary rocks are stratified rocks and they do not exist in crystals. They contain fossils of plants and animals but are not formed in upland areas.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>17","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"A composite cone is a volcano having successive layers of","images":[],"options":{"A":"ash and cinder only","B":"cinder, ash and pyroclasts","C":"ash, acid lava and parasitic cones","D":"pyroclasts and parasitic cones"},"answer":"C","explanation":"A composite cone, also called straso-volcanoe is a major extrusive landform of vulcanicity. It is made up of alternate layers of ash, acid lava and parasitic cones.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>18","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"A mountain that has been denuded is called","images":[],"options":{"A":"a horst","B":"a fold mountain","C":"an intermontane","D":"a residual mountain"},"answer":"D","explanation":"Residual mountains are formed from already existing mountains which are lowered or reduced by agents of denudation such as running water, ice and wind.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>19","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following affects the flow of ocean currents?","images":[],"options":{"A":"Latitude","B":"Humidity","C":"Longitude","D":"Earth's rotation"},"answer":"D","explanation":"Ocean currents are caused by; planetary winds, rotation of the earth, temperature differences, salinity and the shape of the landmasses.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>20","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A wave which retreats after hitting the coast is called","images":[],"options":{"A":"backwash","B":"swash","C":"undertow","D":"trough"},"answer":"A","explanation":"Backwash is the wave which retreats after hitting the coast. It is the water that sucks back and retreats after wash.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>21","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The atmospheric condition of a place over a long period of time refers to its","images":[],"options":{"A":"temperature","B":"weather","C":"pressure","D":"climate"},"answer":"D","explanation":"The climate is defined as the average weather conditions of a place over a long period of time. The weather of any given place changes  from day to day while climate is comparatively constant over a long time.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1998>22","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following weather elements is paired with the wrong instrument?","images":[],"options":{"A":"Atmospheric pressure and barometer","B":"Humidity and anemometer","C":"Rainfall and rain gauge","D":"Wind direction and wind vane"},"answer":"B","explanation":"Humidity is the amount of water vapor present in the air. It is measured using a hygrometer, not an anemometer. An anemometer is used to measure wind speed.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>23","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The major useful component of the atmosphere is","images":[],"options":{"A":"neon","B":"air","C":"dust particles","D":"oxygen"},"answer":"D","explanation":"The major useful component of the atmosphere is oxygen. It is required for a lot of processes e.g photosynthesis, combustion, respiration etc.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1998>24","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The sunshine duration of a place is recorded by a","images":[],"options":{"A":"cup anemometer","B":"sundial","C":"sunshine recorder","D":"thermometer"},"answer":"B","explanation":"Sundial is used to measure the sunshine duration of a place.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>25","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"In humid climates, the process by which dissolved minerals in a horizon of the soil are transported downwards is known as","images":[],"options":{"A":"leaching","B":"calcification","C":"oxidation","D":"transpiration"},"answer":"A","explanation":"The downward transportation of dissolved minerals in a horizon of a soil profile is known as leaching.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>26","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following crops requires sandy, porous and well aerated soils for growth?","images":[],"options":{"A":"Tea","B":"Coffee","C":"Rice","D":"Groundnut"},"answer":"D","explanation":"Groundnut requires sandy, porous and well aerated soils for growth. Sandy soils are well-drained and have large pore spaces that allow for good aeration. This is ideal for groundnut as it allows the roots to penetrate deeply and easily into the soil.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>27","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The substance that cements soil particles together is","images":[],"options":{"A":"air","B":"nutrients","C":"sand","D":"colloid"},"answer":"D","explanation":"Soil colloids are the most active constituent of the soil and they determine the physical and chemical properties of the soil. It also cements soil particles together.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>28","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Soils of the rain forest are rich in humus because of the","images":[],"options":{"A":"multiple species of trees","B":"dense vegetation cover","C":"large quantity of decayed leaves","D":"absence of sunlight at the surface"},"answer":"C","explanation":"The presence of dead and decaying leaves accounts for the rich humus content of the soils of the rainforest.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>29","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The vegetation belt associated with valuable hard wood is the","images":[],"options":{"A":"Sahel Savanna","B":"Tropical rainforest","C":"Coniferous forest","D":"Mediterranean forest"},"answer":"B","explanation":"The vegetation belt associated with valuable hard wood is the Tropical rainforest. Hardwood trees, which are known for their dense and durable wood, are predominantly found in tropical rainforests. These forests are characterized by high rainfall and year-round warm temperatures, conditions that are ideal for the growth of a wide variety of trees, including hardwood species.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>30","subject":"Geography","year":"1998","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Temperate grasslands are generally important for","images":[],"options":{"A":"mining","B":"floating of logs","C":"animal grazing","D":"processing of meat and cheese"},"answer":"C","explanation":"Temperate grasslands are generally important for animal grazing. These areas are characterized by their grassy vegetation and lack of trees or large shrubs. They are known for their rich soils which are beneficial for grass growth. This makes them ideal for grazing animals, both wild and domesticated.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1998>31","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The greatest problem in the use of solar energy is","images":[],"options":{"A":"the high risk in its usage","B":"its unreliability from day to day and season to season","C":"the high intensity associatated with the sun","D":"the high cost of transporting it for domestic use"},"answer":"B","explanation":"Solar energy is a renewable source of energy that is harnessed from the sun. However, its main drawback is its unreliability from day to day and season to season. This is because the amount of sunlight is dependent on the time of day, weather conditions, and the season of the year. Therefore, during cloudy or rainy days and during winter, the amount of energy that can be harnessed is significantly reduced.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>32","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The sparse population in the Amazon Basin is best explained by the","images":[],"options":{"A":"very high tmperature all the year round","B":"low range of temperature for agriculture","C":"thick vegetation for settlements and agriculture","D":"high relief and rugged terrain"},"answer":"C","explanation":"The Amazon Basin  has few people as inhabitants due to thick vegetation for settlements and agriculture.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>33","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"One danger about the present rate of increase in world population is","images":[],"options":{"A":"an improved standard of living","B":"the fear of submergence of the earth","C":"the high ratio of adults to children","D":"an acute food shortage"},"answer":"D","explanation":"The population is increasing at a geometric progression which food production is at an arithmetic progression. The rate of increase in world population will lead to an acute food shortage","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>34","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"A rapid population growth in a region can be caused by","images":[],"options":{"A":"more deaths than births","B":"high emigration","C":"the use of family planning methods","D":"improved medical care"},"answer":"D","explanation":"A rapid population growth in a region can be caused by improved medical care. This is because improved medical care can lead to a decrease in death rates and an increase in birth rates, which can result in a rapid population growth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>35","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following represents an urban-rural migration?","images":[],"options":{"A":"A student from the village school gains admission to the university in the town","B":"Moving to the urban centre for medical service","C":"Travelling from Lagos to the village on retirement","D":"A civil servant gets transfered from one town to another"},"answer":"C","explanation":"An urban-rural migration is the movement of people from urban centres to rural areas. Travelling from Lagos an urban centre to the village, a rural area for retirement is an example of urban-rural migration.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>36","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A rural settlement is a settlement classified by","images":[],"options":{"A":"age","B":"site","C":"altitude","D":"function"},"answer":"D","explanation":"A rural settlement is a settlement classified by type or function. The other type of settlement is called the urban settlement.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1998>37","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Which of the following settlement types is strongly associated with tourism?","images":[],"options":{"A":"Rural settlement","B":"Commercial centre","C":"Port town","D":"Holiday resort"},"answer":"D","explanation":"Holiday resort towns are places of interest where people(tourists) can visit e.g Ikogosi(onso state), Brighton(U.K), Miami(U.S.A) etc.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>38","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Air transportation has a low patronage because it","images":[],"options":{"A":"is fast","B":"is irregular","C":"is useful in war time only","D":"is costly"},"answer":"D","explanation":"Air transportation has a low patronage because it is costly. The cost of air travel is generally higher than other forms of transportation, making it less accessible to a large portion of the population. The other options like being fast, irregular, or useful in war time only do not explain the low patronage.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>39","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"All the following are light industries except","images":[],"options":{"A":"ship building , locomotive and chemicals","B":"printing, flour-milling and furniture -making","C":"locomotives, electionics and texiles","D":"paper, furniture and electronics"},"answer":"A","explanation":"Light industries are those that can be performed with less capital and space, and do not require heavy machinery. They usually produce small consumer goods. Ship building, locomotive and chemicals are examples of heavy industries because they require large amounts of capital, space, and heavy machinery. The other options like printing, flour-milling and furniture-making, locomotives, electronics and textiles, paper, furniture and electronics are examples of light industries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>40","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"One major problem of development in the Niger-Benue trough is","images":[],"options":{"A":"inadequate rainfall","B":"very high relief","C":"desert encroachment","D":"excesive flooding"},"answer":"D","explanation":"The Niger-Benue trough is found in the Niger-Benue valleys. The region which is an elongated and bow shaped lowland is hardly dissected by erosion. The problem of excesive flooding leads to erosion.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>41","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Which of the following modes of transportation in Nigeria is limited by weather?","images":[],"options":{"A":"water","B":"pipeline","C":"road","D":"air"},"answer":"D","explanation":"Air transportation is highly dependent on weather conditions. Poor visibility due to fog, heavy rain, or strong winds can delay or cancel flights. Therefore, among the options provided, air transportation is the most limited by weather.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>42","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Irrigation farming is highly practiced in Northern Nigeria because of the","images":[],"options":{"A":"aboundant plains for the cultivation","B":"limited maret for its products","C":"inadequate rainfall and presence of many rivers","D":"good roads and aboundant capital"},"answer":"C","explanation":"Irrigation in Northern Nigeria is due to the inadequacy of rainfall and the presence of many rivers.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>43","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : WEATHER AND CLIMATE","question":"One important consequence of the location of Nigeria between latitudes 40 and 140 north of the Equator is that she","images":[],"options":{"A":"enjoys a hot, wet, tropical climate","B":"has a luxuriant vegetation","C":"has the north easterly winds prevailling throughout the year","D":"receives rainfall throughout the year"},"answer":"A","explanation":"Nigeria enjoys a hot, wet, tropical climate as a result of her location  between latitudes 40 and 140 north of the Equator.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>44","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following is true of manufacturing industries in Nigeria?","images":[],"options":{"A":"Most of them produce consumer goods","B":"Large quantities of their products are exported","C":"They depend entirely on local raw materials","D":"They were established in pre-colonial times"},"answer":"A","explanation":"The characteristics of manufacturing industries in Nigeria are: emphasis is on production of consumer goods, their produce are mainly consumed in the local markets, they do not easily source their raw materials from within the country, they were not established in pre-colonial times and they are concentrated only in few locations especially in urban centres.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1998>45","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Trade among west African countries is less developed mainly because","images":[],"options":{"A":"they were ruled by different colonial powers which created a barrier to communication","B":"the products of one country are basically similar to those of the others","C":"there are no international railway lines to transport the bulky items of trade across the borders","D":"of ethnic sentiments of people in one country against the other"},"answer":"B","explanation":"Trade among west African countries is less developed due to the production of similar commodities. This limits the volume of trade between them.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>46","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The southern most latitude in Africa is approximately","images":[],"options":{"A":"20oS","B":"30oS","C":"35oS","D":"40oS"},"answer":"C","explanation":"The southern most latitude in Africa is approximately 35oS","marks":"1","difficulty":"1"},{"id":"objective>Geography>1998>47","subject":"Geography","year":"1998","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following does not explain the poor development of inland waterways in Africa?","images":[],"options":{"A":"Lack of goods to carry along the routes","B":"Presence of rapids and waterfalls","C":"Obstruction by floating vegetation","D":"High seasonality of the rivers"},"answer":"A","explanation":"Lack of goods to carry along the routes does not explain the poor development of inland waterways in Africa.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>48","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"The savanna lands of East Africa are best known for their","images":[],"options":{"A":"wildlife","B":"rich mineral resources","C":"inter-ethnic wars","D":"large rivers"},"answer":"A","explanation":"The savanna lands of East Africa is characterized by the presence of its beautiful wildlife. A large East African Savanna wilderness can provide home to tens of thousands of elephants, hippos, giraffe and buffalo.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1998>49","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"The rampant famine in some parts of Africa is caused by all the following except","images":[],"options":{"A":"Unstable prices paid to farmers for their products","B":"Unreliable rainfall","C":"Civil strife and unrest","D":"Ravage of corps by pests"},"answer":"A","explanation":"Unreliable rainfall, Civil strife and unrest,Ravage of corps by pests and soil erosion are causes of rampant famine in some parts of Africa. The Unstable prices paid to farmers doesn't really cause famine in such parts.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1998>50","subject":"Geography","year":"1998","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Which of the following West Africa countries is the largest producer of groundnut?","images":[],"options":{"A":"Burkina Faso","B":"Mali","C":"Guinea Bissau","D":"Senegal"},"answer":"B","explanation":"In Mali, groundnut is grown for both household consumption and sale, accounting for roughly half of a rural household's cash income. Of all the listed options, Mali is the largest producer of groundnut","marks":"1","difficulty":"2"}];